kL,WAAU,KACflL,IAAAC,cAACoK,GAAG,OAENc,SAASC,eAAe,U,mBCV1BC,EAAOC,QAAU,IAA0B,oC,mBCA3CD,EAAOC,QAAU,IAA0B,oC,mBCA3CD,EAAOC,QAAU,IAA0B,oC,mBCA3CD,EAAOC,QAAU,IAA0B,oC,mBCA3CD,EAAOC,QAAU,IAA0B,oC,mBCA3CD,EAAOC,QAAU,IAA0B,oC,mBCA3CD,EAAOC,QAAU,IAA0B,oC,mBCA3CD,EAAOC,QAAU,IAA0B,oC,mBCA3CD,EAAOC,QAAU,IAA0B,oC,mBCA3CD,EAAOC,QAAU,IAA0B,qC,mBCA3CD,EAAOC,QAAU,IAA0B,qC,mBCA3CD,EAAOC,QAAU,IAA0B,qC,mBCA3CD,EAAOC,QAAU,IAA0B,qC,mBCA3CD,EAAOC,QAAU,IAA0B,oC","file":"static/js/main.76a35e85.chunk.js","sourcesContent":["\r\nimport decode from 'jwt-decode';\r\n\r\n\r\nclass AuthService {\r\n\r\n  getProfile() {\r\n    return decode(this.getToken());\r\n  }\r\n\r\n  loggedIn() {\r\n    const token = this.getToken();\r\n    return !!token && !this.isTokenExpired(token); \r\n  }\r\n\r\n  isTokenExpired(token) {\r\n    try {\r\n      const decoded = decode(token);\r\n      if (decoded.exp < Date.now() / 1000) {\r\n        return true;\r\n      } else return false;\r\n    } catch (err) {\r\n      return false;\r\n    }\r\n  }\r\n\r\n  getToken() {\r\n\r\n    return localStorage.getItem('id_token');\r\n  }\r\n\r\n  login(idToken) {\r\n    localStorage.setItem('id_token', idToken);\r\n    window.location.assign('/');\r\n  }\r\n\r\n  logout() {\r\n    localStorage.removeItem('id_token');\r\n    window.location.assign('/');\r\n  }\r\n}\r\n\r\nexport default new AuthService();\r\n","import React from 'react';\r\nimport Auth from '../utils/auth';\r\nimport { Link } from 'react-router-dom';\r\nimport { Navbar, Nav, Container } from 'react-bootstrap';\r\n//import Signup from '../pages/Signup';\r\n// import Login from './pages/Login';\r\n\r\n\r\nconst Navs= () => {\r\n\r\n  return (\r\n    <>\r\n      <Navbar bg='primary' variant='dark' expand='lg'>\r\n        <Container fluid>\r\n          <Navbar.Brand as={Link} to='/'>\r\n           Photo by Vinay\r\n          </Navbar.Brand>\r\n          <Navbar.Toggle aria-controls='navbar' />\r\n          <Navbar.Collapse id='navbar'>\r\n            <Nav className='ml-auto'>\r\n              <Nav.Link as={Link} to='/'>Home</Nav.Link>\r\n              <Nav.Link href=\"about\">About</Nav.Link>\r\n              <Nav.Link href=\"services\">Services</Nav.Link>             \r\n              <Nav.Link href=\"contact\">Contact</Nav.Link>\r\n              <Nav.Link href=\"login\">Login</Nav.Link>\r\n              <Nav.Link href=\"signup\">Signup</Nav.Link>\r\n              {Auth.loggedIn() ? (\r\n                <>\r\n                  <Nav.Link as={Link} to='/'>\r\n                    Home\r\n                  </Nav.Link>\r\n                  <Nav.Link href=\"profile\">Profile</Nav.Link>\r\n                  <Nav.Link onClick={Auth.logout}>Logout</Nav.Link>\r\n                </>\r\n              ) : ( <Nav.Link href=\"#\">#</Nav.Link>)}\r\n            </Nav>\r\n          </Navbar.Collapse>\r\n        </Container>\r\n      </Navbar>\r\n      \r\n    </>\r\n  );\r\n};\r\n\r\nexport default Navs;\r\n","import React from \"react\";\r\nimport { ImageList, ImageListItem } from \"@material-ui/core\";\r\n\r\nimport Image1 from '../assets/img/image1.jpg';\r\nimport Image2 from '../assets/img/image2.jpg';\r\nimport Image3 from '../assets/img/image3.jpg';\r\nimport Image4 from '../assets/img/image4.jpg';\r\nimport image5 from '../assets/img/image5.jpg';\r\nimport image6 from '../assets/img/image6.jpg';\r\nimport image7 from '../assets/img/image7.jpg';\r\nimport image8 from '../assets/img/image8.jpg';\r\nimport image9 from '../assets/img/image9.jpg';\r\nimport Image10 from '../assets/img/image10.jpg';\r\nimport Image11 from '../assets/img/image11.jpg';\r\nimport image12 from '../assets/img/image12.jpg';\r\n// import image13 from '../assets/img/image13.jpg';\r\n\r\n\r\nconst HomeGallery = () => {\r\n\r\n    let data =[\r\n        {    \r\n            \"id\": 1,\r\n            \"imgSrc\": Image1,\r\n            rows: 3,\r\n            cols: 3,\r\n            featured: true,\r\n        },\r\n        {    \r\n            \"id\": 2,\r\n            \"imgSrc\": Image2,\r\n        },\r\n        {    \r\n            \"id\": 3,\r\n            \"imgSrc\": Image3,\r\n        },\r\n        {    \r\n            \"id\": 4,\r\n            \"imgSrc\": Image4,\r\n            rows: 3,\r\n            cols: 3,\r\n            featured: true,\r\n        },\r\n        {    \r\n            \"id\": 5,\r\n            \"imgSrc\": image5,\r\n        },\r\n        {    \r\n            \"id\": 6,\r\n            \"imgSrc\": image6,\r\n            \r\n        },\r\n        {    \r\n            \"id\": 7,\r\n            \"imgSrc\": image7,\r\n            rows: 3,\r\n            cols: 3,\r\n        },\r\n        {    \r\n            \"id\": 8,\r\n            \"imgSrc\": image8,\r\n        },\r\n        {    \r\n            \"id\": 9,\r\n            \"imgSrc\": image9,\r\n        },\r\n        {    \r\n            \"id\": 10,\r\n            \"imgSrc\": Image10,\r\n            rows: 3,\r\n            cols: 3,\r\n        },\r\n        {    \r\n            \"id\": 11,\r\n            \"imgSrc\": Image11,\r\n        },\r\n        {    \r\n            \"id\": 12,\r\n            \"imgSrc\": image12,\r\n        },\r\n        {    \r\n           \r\n        },\r\n    ];\r\n    return (\r\n        <ImageList sx={{ width: 500, height: 450 }} >\r\n            <ImageListItem  style={{width: '100%', height:'100%', position: 'absolute'}} cols={3}>\r\n                {data.map((item, index) =>{ \r\n                    return(                        \r\n                        <img className=\"img\"\r\n                            src={`${item.imgSrc}`}\r\n                            srcSet={`${item.imgSrc}`}\r\n                            alt={item.title}\r\n                            loading=\"lazy\"/>\r\n                        )\r\n                  })}\r\n            </ImageListItem>\r\n       </ImageList>\r\n    )\r\n}\r\n\r\nexport default HomeGallery","\r\nimport React from 'react';\r\nimport Profile from \"../assets/img/profile.jpg\";\r\n\r\nfunction About() {\r\n  return (\r\n    <div className=\"container center\">\r\n      <h2>About Me</h2>\r\n      <div className=\"about-body\">\r\n\r\n      <img src={Profile} alt=\"Pic\"></img>\r\n        <div className=\"bodyTab pTag\">\r\n          <h3>Vinay Vallabhaneni</h3>\r\n          <p>The essence of photography is for the photographer to share the world through their eyes; \r\n            a way for their viewers to see what they feel and evoke a similar or same emotion. \r\n            To capture people or places we will not see again. Think about a time that you saw a photograph, \r\n            maybe one that was taken of a beloved relative during an event like a casual family gathering. \r\n            Think about all the emotions you felt while looking at that one simple photo. Certainly there were many and you \r\n            felt what the photographer was feeling.\r\n          </p>\r\n          <div className='padding'>\r\n            <p>Vinay loves photography and coding</p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  );\r\n}\r\n\r\nexport default About;","import React from 'react';\r\nimport MyPDF from '../assets/downloads/vinay.pdf';\r\n\r\nfunction Resume() {\r\n    return (\r\n        <section className=\"mb-5 center\">\r\n            <h2 className=\"resume\">Resume</h2>\r\n            <div className=\"resume\">Download <a href={MyPDF} download=\"My_File.pdf\"> Resume </a></div>\r\n            <div className=\"resume\">\r\n                <div className=\"resume\">\r\n                    <h3> <b>UI Skills</b> </h3>\r\n                    <ul className=\"skills\">\r\n                        <li>HTML</li>\r\n                        <li>CSS</li>\r\n                        <li>JavaScript</li>\r\n                        <li>jQuery</li>                        \r\n                        <li>Bootstrap</li>                       \r\n                        <li>Responsive Design</li>\r\n                        <li>Angular</li>\r\n                        <li>React</li>\r\n                        <li>Node.js</li>\r\n                        <li>Jenkins</li>\r\n                        <li>Git</li>\r\n                    </ul>\r\n                </div>              \r\n            </div>\r\n        </section>\r\n    );\r\n};\r\n\r\nexport default Resume;","import React from 'react'\r\n\r\nexport default function Profile() {\r\n\r\n\r\n  return (\r\n    <div className='container multi-container'>\r\n         <div>\r\n             <img src={`https://robohash.org/random.png?size=200x200`} alt=\"pic\" />\r\n             <h5>Vinay Vallabhaneni</h5>\r\n         </div>\r\n         <div>Comments Section</div>\r\n         <blockquote>\r\n             <h6>My Comments</h6>\r\n             <p>Vinay</p>\r\n         </blockquote>\r\n    </div>\r\n  )\r\n}\r\n","import React, {useState} from 'react';\r\nimport { validateEmail, capitalizeFirstLetter } from \"../utils/helpers\";\r\n\r\n\r\nfunction Contact() {\r\n  const [formState, setFormState] = useState({ name: '', email: '', message: '' });\r\n  const { name, email, message } = formState;\r\n  const [errorMessage, setErrorMessage] = useState('');\r\n\r\n  function handleChange(e) {\r\n    if (e.target.name === 'email') {\r\n      const isValid = validateEmail(e.target.value);\r\n\r\n      if (!isValid) {\r\n        setErrorMessage('Please enter a valid email');\r\n      } else {\r\n        setErrorMessage('');\r\n      }\r\n    }\r\n    else {\r\n      if (!e.target.value.length) {\r\n        setErrorMessage(`${capitalizeFirstLetter(e.target.name)} is required`);\r\n      } else {\r\n        setErrorMessage('');\r\n      }\r\n    }\r\n    if (!errorMessage) {\r\n      setFormState({ ...formState, [e.target.name]: e.target.value })\r\n    }\r\n  }\r\n\r\n  async function handleSubmit(e) {\r\n    e.preventDefault();\r\n\r\n    await fetch(`/send`, {\r\n      method: \"POST\",\r\n      headers: {\r\n        \"Content-Type\": \"application/json\"\r\n      },\r\n      body: JSON.stringify({\r\n        name: formState.name,\r\n        email: formState.email,\r\n        message: formState.message\r\n      })\r\n    })\r\n    .then((res) => res.json())\r\n    .then(async (res) => {\r\n      const resData = await res;\r\n      if (resData.status === \"success\") {\r\n        alert(\"Message Sent!\");\r\n      } else if (resData.status === \"fail\") {\r\n        alert(\"Message failed to send\");\r\n      }\r\n    })\r\n    .catch(err => {\r\n      console.log(\"Error: \" + err)\r\n    })\r\n  }\r\n\r\n  return (\r\n    <div className=\"page-div\">\r\n      <h2 className=\"center padTop\">Contact Me</h2>\r\n      <form className=\"form pBody\" onSubmit={handleSubmit}>\r\n        <div>\r\n          <label htmlFor=\"name\" className=\"contact-el fancy\">Name:</label><br />\r\n          <input type=\"text\" name=\"name\" className=\"contact-el\" defaultValue={name} onBlur={handleChange} />\r\n        </div>\r\n        <div>\r\n          <label htmlFor=\"email\" className='fancy'>Email address:</label><br />\r\n          <input type=\"email\" name=\"email\" className=\"contact-el\" defaultValue={email} onBlur={handleChange} />\r\n        </div>\r\n        <div>\r\n          <label htmlFor=\"message\" className=\"contact-el fancy\">Message:</label><br />\r\n          <textarea name=\"message\" className=\"contact-el fancy\" defaultValue={message} onBlur={handleChange} />\r\n        </div>\r\n        {errorMessage && (\r\n          <div>\r\n            <p className=\"errorMsg contact-el\">\r\n            \r\n              {errorMessage}</p>\r\n          </div>\r\n        )}\r\n        <button type=\"submit\" className=\"submit-contact contact-el fancy\">Submit</button>\r\n      </form>\r\n    </div>\r\n  );\r\n}\r\n\r\nexport default Contact;","export function capitalizeFirstLetter(string) {\r\n    return string.charAt(0).toUpperCase() + string.slice(1);\r\n  }\r\n  \r\n  export function validateEmail(email) {\r\n    var re = /^(([^<>()[\\]\\\\.,;:\\s@\"]+(\\.[^<>()[\\]\\\\.,;:\\s@\"]+)*)|(\".+\"))@((\\[[0-9]{1,3}\\.[0-9]{1,3}\\.[0-9]{1,3}\\.[0-9]{1,3}\\])|(([a-zA-Z\\-0-9]+\\.)+[a-zA-Z]{2,}))$/;\r\n    return re.test(String(email).toLowerCase());\r\n  }","import gql from 'graphql-tag';\r\n\r\nexport const LOGIN_USER = gql`\r\n  mutation login($email: String!, $password: String!) {\r\n    login(email: $email, password: $password) {\r\n      token\r\n      user {\r\n        _id\r\n        username\r\n      }\r\n    }\r\n  }\r\n`;\r\n\r\nexport const ADD_USER = gql`\r\n  mutation addUser($username: String!, $email: String!, $password: String!) {\r\n    addUser(username: $username, email: $email, password: $password) {\r\n      token\r\n      user {\r\n        _id\r\n        username\r\n      }\r\n    }\r\n  }\r\n`;\r\n\r\nexport const SAVE_Comment = gql`\r\n  mutation saveComment($commentData: CommentInput!) {\r\n    saveComment(commentData: $commentData) {\r\n      _id\r\n      username\r\n      email\r\n      savedComments {\r\n        commentId\r\n        authors\r\n        image\r\n        description\r\n        title\r\n        link\r\n      }\r\n    }\r\n  }\r\n`;\r\n\r\nexport const REMOVE_Comment = gql`\r\n  mutation removeComment($commentId: ID!) {\r\n    removeComment(commentId: $commentId) {\r\n      _id\r\n      username\r\n      email\r\n      savedComments {\r\n        commentId\r\n        authors\r\n        image\r\n        description\r\n        title\r\n        link\r\n      }\r\n    }\r\n  }\r\n`;\r\n","import React, { useState, useEffect } from 'react';\r\nimport { Form, Button, Alert } from 'react-bootstrap';\r\nimport { Link } from 'react-router-dom';\r\nimport { useMutation } from '@apollo/react-hooks';\r\nimport { ADD_USER } from '../utils/mutations';\r\nimport Auth from '../utils/auth';\r\n\r\nconst Signup = () => {\r\n  const [userFormData, setUserFormData] = useState({ username: '', email: '', password: '' });\r\n  const [validated] = useState(false);\r\n  const [showAlert, setShowAlert] = useState(false);\r\n\r\n  const [addUser, { error }] = useMutation(ADD_USER);\r\n\r\n  useEffect(() => {\r\n    if (error) {\r\n      setShowAlert(true);\r\n    } else {\r\n      setShowAlert(false);\r\n    }\r\n  }, [error]);\r\n\r\n  const handleInputChange = (event) => {\r\n    const { name, value } = event.target;\r\n    setUserFormData({ ...userFormData, [name]: value });\r\n  };\r\n\r\n  const handleFormSubmit = async (event) => {\r\n    event.preventDefault();\r\n\r\n    const form = event.currentTarget;\r\n    if (form.checkValidity() === false) {\r\n      event.preventDefault();\r\n      event.stopPropagation();\r\n    }\r\n\r\n    try {\r\n      const { data } = await addUser({\r\n        variables: { ...userFormData },\r\n      });\r\n      console.log(data);\r\n      Auth.login(data.addUser.token);\r\n    } catch (err) {\r\n      console.error(err);\r\n    }\r\n\r\n    setUserFormData({\r\n      username: '',\r\n      email: '',\r\n      password: '',\r\n    });\r\n  };\r\n\r\n  return (\r\n    <>\r\n    <Link to=\"/login\">← Go to Login</Link>\r\n      <Form noValidate validated={validated} onSubmit={handleFormSubmit}>\r\n        <Alert dismissible onClose={() => setShowAlert(false)} show={showAlert} variant='danger'>\r\n          Something went wrong with your signup!\r\n        </Alert>\r\n\r\n        <Form.Group>\r\n          <Form.Label htmlFor='username'>Username</Form.Label>\r\n          <Form.Control\r\n            type='text'\r\n            placeholder='Your username'\r\n            name='username'\r\n            onChange={handleInputChange}\r\n            value={userFormData.username}\r\n            required\r\n          />\r\n          <Form.Control.Feedback type='invalid'>Username is required!</Form.Control.Feedback>\r\n        </Form.Group>\r\n\r\n        <Form.Group>\r\n          <Form.Label htmlFor='email'>Email</Form.Label>\r\n          <Form.Control\r\n            type='email'\r\n            placeholder='Your email address'\r\n            name='email'\r\n            onChange={handleInputChange}\r\n            value={userFormData.email}\r\n            required\r\n          />\r\n          <Form.Control.Feedback type='invalid'>Email is required!</Form.Control.Feedback>\r\n        </Form.Group>\r\n\r\n        <Form.Group>\r\n          <Form.Label htmlFor='password'>Password</Form.Label>\r\n          <Form.Control\r\n            type='password'\r\n            placeholder='Your password'\r\n            name='password'\r\n            onChange={handleInputChange}\r\n            value={userFormData.password}\r\n            required\r\n          />\r\n          <Form.Control.Feedback type='invalid'>Password is required!</Form.Control.Feedback>\r\n        </Form.Group>\r\n        <Button\r\n          disabled={!(userFormData.username && userFormData.email && userFormData.password)}\r\n          type='submit'\r\n          variant='success'>\r\n          Submit\r\n        </Button>\r\n      </Form>\r\n    </>\r\n  );\r\n};\r\n\r\nexport default Signup;\r\n","import React, { useState, useEffect } from 'react';\r\nimport { Form, Button, Alert } from 'react-bootstrap';\r\n\r\nimport { useMutation } from '@apollo/react-hooks';\r\nimport { LOGIN_USER } from '../utils/mutations';\r\nimport Auth from '../utils/auth';\r\n\r\nconst Login = () => {\r\n  const [userFormData, setUserFormData] = useState({ email: '', password: '' });\r\n  const [validated] = useState(false);\r\n  const [showAlert, setShowAlert] = useState(false);\r\n  const [login, { error }] = useMutation(LOGIN_USER);\r\n\r\n  useEffect(() => {\r\n    if (error) {\r\n      setShowAlert(true);\r\n    } else {\r\n      setShowAlert(false);\r\n    }\r\n  }, [error]);\r\n\r\n  const handleInputChange = (event) => {\r\n    const { name, value } = event.target;\r\n    setUserFormData({ ...userFormData, [name]: value });\r\n  };\r\n\r\n  const handleFormSubmit = async (event) => {\r\n    event.preventDefault();\r\n\r\n    const form = event.currentTarget;\r\n    if (form.checkValidity() === false) {\r\n      event.preventDefault();\r\n      event.stopPropagation();\r\n    }\r\n\r\n    try {\r\n      const { data } = await login({\r\n        variables: { ...userFormData },\r\n      });\r\n\r\n      console.log(data);\r\n      Auth.login(data.login.token);\r\n    } catch (e) {\r\n      console.error(e);\r\n    }\r\n\r\n    setUserFormData({\r\n      email: '',\r\n      password: '',\r\n    });\r\n  };\r\n\r\n  return (\r\n    <>\r\n      <Form noValidate validated={validated} onSubmit={handleFormSubmit}>\r\n        <Alert dismissible onClose={() => setShowAlert(false)} show={showAlert} variant='danger'>\r\n          Something went wrong with your login credentials!\r\n        </Alert>\r\n        <Form.Group>\r\n          <Form.Label htmlFor='email'>Email</Form.Label>\r\n          <Form.Control\r\n            type='text'\r\n            placeholder='Your email'\r\n            name='email'\r\n            onChange={handleInputChange}\r\n            value={userFormData.email}\r\n            required\r\n          />\r\n          <Form.Control.Feedback type='invalid'>Email is required!</Form.Control.Feedback>\r\n        </Form.Group>\r\n\r\n        <Form.Group>\r\n          <Form.Label htmlFor='password'>Password</Form.Label>\r\n          <Form.Control\r\n            type='password'\r\n            placeholder='Your password'\r\n            name='password'\r\n            onChange={handleInputChange}\r\n            value={userFormData.password}\r\n            required\r\n          />\r\n          <Form.Control.Feedback type='invalid'>Password is required!</Form.Control.Feedback>\r\n        </Form.Group>\r\n        <Button disabled={!(userFormData.email && userFormData.password)} type='submit' variant='success'>\r\n          Submit\r\n        </Button>\r\n      </Form>\r\n    </>\r\n  );\r\n};\r\n\r\nexport default Login;\r\n","import React from 'react';\r\nimport { BrowserRouter as Router, Routes, Route } from 'react-router-dom';\r\nimport NavBar from './components/NavBar.js';\r\nimport Home from './pages/Home.js';\r\nimport About from './pages/About.js';\r\nimport Services from './pages/Services.js';\r\nimport Profile from './pages/Profile.js';\r\nimport Contact from './pages/Contact.js';\r\n// import SearchComments from './pages/SearchComments';\r\n// import SavedComments from './pages/SavedComments';\r\nimport Signup from './pages/Signup';\r\nimport Login from './pages/Login';\r\nimport { ApolloProvider } from '@apollo/react-hooks';\r\nimport ApolloClient from 'apollo-boost';\r\n\r\nconst client = new ApolloClient({\r\n  request: (operation) => {\r\n    const token = localStorage.getItem('id_token');\r\n\r\n    operation.setContext({\r\n      headers: {\r\n        authorization: token ? `Bearer ${token}` : '',\r\n      },\r\n    });\r\n  },\r\n  uri: '/graphql',\r\n});\r\n\r\nfunction App() {\r\n\r\n  return (\r\n    <ApolloProvider client={client}>\r\n    <Router>\r\n      <>\r\n        <NavBar />\r\n        <Routes> \r\n          <Route exact path=\"/\" element={<Home />} />\r\n          <Route exact path='/Home' element={<Home />} />\r\n          <Route exact path=\"/About\" element={<About />} />\r\n          <Route exact path=\"/Services\" element={<Services />} />\r\n          <Route exact path=\"/Profile\" element={<Profile />} />\r\n          <Route exact path=\"/Contact\" element={<Contact />} />\r\n          {/* <Route exact path='/' component={SearchComments} />\r\n          <Route exact path='/SavedComments' component={SavedComments} /> */}\r\n          <Route exact path=\"/Login\" element={<Login />} />\r\n          <Route exact path=\"/Signup\" element={<Signup />} />\r\n          <Route render={() => <h1 className='display-4'>Something went Wrong!</h1>} />\r\n        </Routes>\r\n      </>\r\n    </Router>\r\n    </ApolloProvider>\r\n  );\r\n}\r\n\r\nexport default App;\r\n","import React from \"react\";\r\nimport ReactDOM from \"react-dom\";\r\nimport \"bootstrap/dist/css/bootstrap.min.css\";\r\nimport \"./index.css\";\r\nimport App from \"./App\";\r\n\r\nReactDOM.render(\r\n  <React.StrictMode>\r\n    <App />\r\n  </React.StrictMode>,\r\n  document.getElementById(\"root\"),\r\n);\r\n","module.exports = __webpack_public_path__ + \"static/media/image1.8a06fd7f.jpg\";","module.exports = __webpack_public_path__ + \"static/media/image2.14952cac.jpg\";","module.exports = __webpack_public_path__ + \"static/media/image3.d7f121cf.jpg\";","module.exports = __webpack_public_path__ + \"static/media/image4.bff93489.jpg\";","module.exports = __webpack_public_path__ + \"static/media/image5.4beb1c41.jpg\";","module.exports = __webpack_public_path__ + \"static/media/image6.fd0ee25c.jpg\";","module.exports = __webpack_public_path__ + \"static/media/image7.8227bf0a.jpg\";","module.exports = __webpack_public_path__ + \"static/media/image8.6897f62f.jpg\";","module.exports = __webpack_public_path__ + \"static/media/image9.5451ac14.jpg\";","module.exports = __webpack_public_path__ + \"static/media/image10.18610184.jpg\";","module.exports = __webpack_public_path__ + \"static/media/image11.e5a9acdf.jpg\";","module.exports = __webpack_public_path__ + \"static/media/image12.7948da58.jpg\";","module.exports = __webpack_public_path__ + \"static/media/profile.40861eb0.jpg\";","module.exports = __webpack_public_path__ + \"static/media/vinay.2e7197c8.pdf\";"],"sourceRoot":""}
